function pad(str) {
	let val=[];
	let size = str.length;
	if(size >= 512)
	{
		size = 512;
	}
	else if(size >= 384)
	{
		size = 384;
	}
	else
	{
		size = 256;
	}
	for (let i=0; i<size; i++)
	{
		val[i] = str[i].toString(16);
		if (val[i].length < 2)
			val[i] = `0${val[i]}`
	}
	return (val.join(' '));
}

